import { SiteFooter } from "@/components/SiteFooter";
import { SectionWrapper } from "@/components/public/SectionWrapper";
import { PremiumCard } from "@/components/public/PremiumCard";
import { CTAStrip } from "@/components/public/CTAStrip";

export const metadata = {
  title: "Leadership Team | Ozeki Reading Bridge Foundation",
  description:
    "Meet the board, staff, and volunteers guiding literacy implementation at Ozeki Reading Bridge Foundation.",
};

export const revalidate = 300;

type Profile = PortalLeadershipTeamMemberRecord;

function ProfileCard({ profile }: { profile: Profile }) {
  const initials = profile.name
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("");

  return (
    <PremiumCard className="flex flex-col h-full bg-white overflow-hidden p-0 rounded-3xl group" withHover>
      {/* Photo Header */}
      <div className="relative w-full aspect-[4/3] bg-gray-100 overflow-hidden">
        {profile.photoFileName ? (
          <img
            src={`/api/about/team/${profile.id}/photo?v=${encodeURIComponent(profile.updatedAt)}`}
            alt={profile.photoAlt || `${profile.name} profile photo`}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500 ease-out"
            loading="lazy"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center bg-[#006b61]/5" aria-hidden="true">
            <span className="text-4xl font-extrabold text-[#006b61]/20 tracking-tighter">{initials}</span>
          </div>
        )}
      </div>

      {/* Content Body */}
      <div className="p-6 md:p-8 flex-grow flex flex-col">
        <h3 className="text-2xl font-bold text-brand-primary mb-1">{profile.name}</h3>
        <p className="text-[#006b61] font-semibold text-sm uppercase tracking-wide mb-4">
          {profile.role}
        </p>

        <p className="text-gray-600 leading-relaxed mb-6 text-sm flex-grow">
          {profile.biography}
        </p>

        {/* Meta Attributes */}
        <div className="pt-5 border-t border-gray-100 mt-auto space-y-3">
          {profile.background && (
            <div className="flex flex-col">
              <span className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Background</span>
              <span className="text-sm text-gray-700 font-medium">{profile.background}</span>
            </div>
          )}
          {profile.career && (
            <div className="flex flex-col">
              <span className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Career</span>
              <span className="text-sm text-gray-700 font-medium">{profile.career}</span>
            </div>
          )}
        </div>
      </div>
    </PremiumCard>
  );
}

export default async function LeadershipTeamPage() {
  let profiles: Profile[] = [];
  try {
    profiles = await listPortalLeadershipTeamMembersPostgres();
  } catch {
    // Database table may not exist yet — show empty state gracefully
  }

  const boardMembers = profiles.filter((profile) => profile.section === "board");
  const staffTeam = profiles.filter((profile) => profile.section === "staff");
  const volunteerTeam = profiles.filter((profile) => profile.section === "volunteer");
  const hasProfiles = profiles.length > 0;

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <SiteHeader />

      <main className="flex-grow pt-[72px] md:pt-20">
        {/* Hero Section */}
        <section className="relative overflow-hidden bg-brand-background pt-24 pb-20 md:pt-32 md:pb-32 border-b border-gray-100">
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-[#006b61]/10 via-brand-background to-brand-background pointer-events-none" />
          <div className="container mx-auto px-4 md:px-6 max-w-5xl relative z-10 text-center">
            <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-[#FA7D15]/10 text-[#FA7D15] font-bold text-sm mb-6 shadow-sm border border-[#FA7D15]/20">
              <Users className="w-4 h-4" /> About Us
            </div>
            <h1 className="text-5xl md:text-7xl font-extrabold text-brand-primary tracking-tight leading-tight mb-8">
              Leadership Team
            </h1>
            <p className="text-xl md:text-2xl text-gray-600 max-w-3xl mx-auto leading-relaxed mb-6">
              Meet the dedicated board members, core staff, and volunteers committed to driving our literacy implementation forward.
            </p>
          </div>
        </section>

        {!hasProfiles ? (
          <SectionWrapper theme="light">
            <div className="max-w-4xl mx-auto text-center py-12">
              <div className="w-20 h-20 rounded-full bg-gray-100 flex items-center justify-center mx-auto mb-6">
                <Users className="w-10 h-10 text-gray-400" />
              </div>
              <h2 className="text-3xl font-bold text-brand-primary mb-4">Leadership profiles will appear here</h2>
              <p className="text-xl text-gray-500 max-w-2xl mx-auto">
                Once records are published from the administrative staff portal, the leadership directory will populate automatically.
              </p>
            </div>
          </SectionWrapper>
        ) : (
          <>
            {/* Board Governance */}
            {boardMembers.length > 0 && (
              <SectionWrapper theme="light" id="board">
                <div className="max-w-7xl mx-auto">
                  <div className="text-center mb-16">
                    <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-[#006b61]/10 text-[#006b61] mb-6">
                      <ShieldCheck className="w-8 h-8" />
                    </div>
                    <h2 className="text-4xl font-bold text-brand-primary mb-4">Board Governance</h2>
                    <p className="text-xl text-gray-600 max-w-2xl mx-auto">
                      Providing strategic accountability, oversight, and guidance to ensure organizational integrity and mission focus.
                    </p>
                  </div>
                  <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {boardMembers.map((profile) => (
                      <ProfileCard key={profile.id} profile={profile} />
                    ))}
                  </div>
                </div>
              </SectionWrapper>
            )}

            {/* Core Staff Team */}
            {staffTeam.length > 0 && (
              <SectionWrapper theme="off-white" id="staff">
                <div className="max-w-7xl mx-auto">
                  <div className="text-center mb-16">
                    <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-[#FA7D15]/10 text-[#FA7D15] mb-6">
                      <HeartPulse className="w-8 h-8" />
                    </div>
                    <h2 className="text-4xl font-bold text-brand-primary mb-4">Core Staff Team</h2>
                    <p className="text-xl text-gray-600 max-w-2xl mx-auto">
                      The professionals designing, managing, and evaluating our programs on the ground every single day.
                    </p>
                  </div>
                  <div className="grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {staffTeam.map((profile) => (
                      <ProfileCard key={profile.id} profile={profile} />
                    ))}
                  </div>
                </div>
              </SectionWrapper>
            )}

            {/* Volunteers */}
            {volunteerTeam.length > 0 && (
              <SectionWrapper theme="light" id="volunteers">
                <div className="max-w-7xl mx-auto">
                  <div className="text-center mb-16">
                    <h2 className="text-4xl font-bold text-brand-primary mb-4">Volunteer Team</h2>
                    <div className="w-24 h-1 bg-[#006b61]/20 mx-auto rounded-full" />
                  </div>
                  <div className="grid sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                    {volunteerTeam.map((profile) => (
                      <ProfileCard key={profile.id} profile={profile} />
                    ))}
                  </div>
                </div>
              </SectionWrapper>
            )}
          </>
        )}

        {/* Global CTA */}
        <CTAStrip 
          heading="Discover our history"
          subheading="Learn about where Ozeki began and how our mission has evolved over the years."
          primaryButtonText="View Our Story"
          primaryButtonHref="/about/our-story"
          primaryButtonColor="bg-[#006b61]"
          primaryButtonHoverColor="hover:bg-[#006b61]/90"
          secondaryButtonText="Back to About"
          secondaryButtonHref="/about"
          theme="light"
        />
      </main>

      <SiteFooter />
    </div>
  );
}

"use server";

import { getCrmAccounts, getAccount360, logInteraction } from "@/lib/server/postgres/repositories/crm";
import { auth } from "@/lib/auth";

export async function fetchCrmAccounts(filters: any) {
  return await getCrmAccounts(filters);
}

export async function fetchAccountDetail(id: string) {
  return await getAccount360(id);
}

export async function addInteraction(data: any) {
  const session = await auth();
  if (!session?.user?.id) throw new Error("Unauthorized");

  return await logInteraction({
    ...data,
    userId: Number(session.user.id)
  });
}

"use server";

import { requirePortalStaffUser } from "@/lib/auth";
import { 
  getStatementOfFinancialPosition, 
  getStatementOfActivities, 
  getCashFlowStatement, 
  getBudgetVsActual, 
  getGrantAndDonorReport 
} from "@/lib/server/postgres/repositories/finance-reports";
import { generateFinancialNarration } from "@/lib/server/ai/finance-narration";
import { generateFinancialPdf, FinancialReportData } from "@/lib/server/pdf/financial-report-puppeteer";

export async function generateFinancialReport(reportType: string, options: { 
  startDate?: string; 
  endDate?: string; 
  asOfDate?: string; 
  fiscalYear?: number;
  budgetPlanId?: number;
  grantId?: number;
}) {
  const user = await requirePortalStaffUser();
  if (!user) throw new Error("Unauthorized");

  const orgName = "Ozeki Reading Bridge Foundation";
  let title = "Financial Report";
  let dataRows: any[] = [];
  let headers: string[] = [];
  let period = "";

  // 1. Fetch Data based on report type
  if (reportType === "BalanceSheet") {
    const date = options.asOfDate || new Date().toISOString().split("T")[0];
    title = "Statement of Financial Position (Balance Sheet)";
    period = `As of ${date}`;
    dataRows = await getStatementOfFinancialPosition(date);
    headers = ["Category", "Account Name", "Balance"];
  } else if (reportType === "PnL") {
    const start = options.startDate || "2024-01-01";
    const end = options.endDate || "2024-12-31";
    title = "Statement of Activities (Income & Expenditure)";
    period = `${start} to ${end}`;
    dataRows = await getStatementOfActivities(start, end);
    headers = ["Type", "Account Name", "Net Amount"];
  } else if (reportType === "CashFlow") {
    const start = options.startDate || "2024-01-01";
    const end = options.endDate || "2024-12-31";
    title = "Cash Flow Statement";
    period = `${start} to ${end}`;
    dataRows = await getCashFlowStatement(start, end);
    headers = ["Activity Category", "Account Name", "Net Cash Impact"];
  } else if (reportType === "BudgetActual") {
    const year = options.fiscalYear || new Date().getFullYear();
    const planId = options.budgetPlanId || 1;
    title = "Budget vs. Actual (Variance Analysis)";
    period = `Fiscal Year ${year}`;
    dataRows = await getBudgetVsActual(year, planId);
    headers = ["Code", "Account Name", "Budget", "Actual", "Variance", "%"];
  } else if (reportType === "Grants") {
    title = "Grant and Donor Utilization Report";
    period = "Life-to-date";
    dataRows = await getGrantAndDonorReport(options.grantId);
    headers = ["Grant", "Fund", "Type", "Account", "Debit", "Credit", "Net Available"];
  }

  // 2. Generate AI Narration
  const narration = await generateFinancialNarration(title, dataRows, { 
    period, 
    organization: orgName 
  });

  // 3. Prepare PDF Data
  const reportData: FinancialReportData = {
    title,
    organization: orgName,
    period,
    narration,
    tables: [
      {
        name: "Main Ledger Summary",
        headers,
        rows: dataRows.map(row => Object.values(row))
      }
    ]
  };

  // 4. Generate PDF
  const pdfBuffer = await generateFinancialPdf(reportData);
  return {
    pdfBase64: pdfBuffer.toString("base64"),
    fileName: `${reportType}_Report_${new Date().getTime()}.pdf`
  };
}

import { notFound } from "next/navigation";
import type { Metadata } from "next";
import { AnthologyPdfViewer } from "@/components/AnthologyPdfViewer";
import Link from "next/link";
import {
    getAnthologyBySlugPostgres,
    listPublishedStoriesByAnthologyPostgres,
} from "@/lib/server/postgres/repositories/public-content";

export const revalidate = 300;

type Params = Promise<{ slug: string }>;

export async function generateMetadata({ params }: { params: Params }): Promise<Metadata> {
    const { slug } = await params;
    const anthology = await getAnthologyBySlugPostgres(slug);

    if (!anthology) {
        return { title: "Anthology Not Found" };
    }

    return {
        title: `${anthology.title} — 1001 Story Library`,
        description: `Read the ${anthology.title} anthology published by the Ozeki Reading Bridge Foundation.`,
        openGraph: {
            title: anthology.title,
            description: `Read the ${anthology.edition ? anthology.edition + " " : ""}anthology from ${anthology.schoolName || anthology.districtScope || "Uganda"}.`,
            type: "article",
            images: anthology.coverImagePath ? [{ url: anthology.coverImagePath }] : [],
        },
    };
}

export default async function AnthologyPage({ params }: { params: Params }) {
    const { slug } = await params;
    const anthology = await getAnthologyBySlugPostgres(slug);

    if (!anthology) {
        notFound();
    }

    const stories = await listPublishedStoriesByAnthologyPostgres(anthology.id);

    return (
        <>
            <section className="page-hero" style={{ paddingBottom: "2rem" }}>
                <div className="container">
                    <nav className="impact-dash-breadcrumb" aria-label="Breadcrumb">
                        <Link href="/stories">1001 Story Library</Link>
                        <span aria-hidden>›</span>
                        <span>{anthology.title}</span>
                    </nav>

                    <div style={{ display: "flex", gap: "2rem", alignItems: "flex-start", marginTop: "2rem", flexWrap: "wrap" }}>
                        {anthology.coverImagePath && (
                            <img
                                src={anthology.coverImagePath}
                                alt=""
                                style={{ width: "200px", borderRadius: "8px", boxShadow: "0 10px 30px rgba(0,0,0,0.1)" }}
                            />
                        )}
                        <div style={{ flex: 1, minWidth: "300px" }}>
                            {anthology.featured && (
                                <span style={{ display: "inline-block", marginBottom: "0.5rem", padding: "0.2rem 0.6rem", backgroundColor: "var(--md-sys-color-primary)", color: "var(--md-sys-color-on-primary)", borderRadius: "99px", fontSize: "0.8rem", fontWeight: "bold", textTransform: "uppercase" }}>
                                    ⭐ Featured Anthology
                                </span>
                            )}
                            <h1 style={{ margin: "0 0 0.5rem 0" }}>{anthology.title}</h1>
                            <p style={{ fontSize: "1.2rem", margin: "0 0 1rem 0", opacity: 0.9 }}>
                                {anthology.edition && <span style={{ fontWeight: 600 }}>{anthology.edition} • </span>}
                                {anthology.scopeType === "school" ? anthology.schoolName : `${anthology.districtScope || anthology.scopeType} Anthology`}
                                {anthology.pdfPageCount > 0 && ` • ${anthology.pdfPageCount} pages`}
                            </p>
                        </div>
                    </div>
                </div>
            </section>

            <section className="section" style={{ backgroundColor: "var(--md-sys-color-surface-container-low)" }}>
                <div className="container" style={{ maxWidth: "1000px" }}>
                    <AnthologyPdfViewer
                        anthology={anthology}
                        stories={stories}
                    />
                </div>
            </section>
        </>
    );
}

import { z } from "zod";
import { getAuthenticatedPortalUser } from "@/lib/auth";
import { RouteError, jsonSuccess, withRouteHandler } from "@/lib/server/http/route-utils";
import { queryPostgres, withPostgresClient } from "@/lib/server/postgres/client";
import type { PortalUser } from "@/lib/types";

export const runtime = "nodejs";

const addToTrainingSchema = z.object({
  contactId: z.coerce.number().int().positive(),
  trainingRecordId: z.coerce.number().int().positive(),
});

async function addContactToTrainingSession(
  actor: PortalUser,
  contactId: number,
  trainingRecordId: number,
) {
  return withPostgresClient(async (client) => {
    await client.query("BEGIN");
    try {
      /* ── Load contact ──────────────────────────────────────────── */
      const contactResult = await client.query<{
        contactId: number;
        contactUid: string;
        schoolId: number;
        fullName: string;
        gender: string;
        phone: string | null;
        email: string | null;
        category: string;
        roleTitle: string | null;
        teacherUid: string | null;
      }>(
        `
          SELECT
            contact_id AS "contactId",
            contact_uid AS "contactUid",
            school_id AS "schoolId",
            full_name AS "fullName",
            CASE
              WHEN lower(COALESCE(gender, '')) = 'male' THEN 'Male'
              WHEN lower(COALESCE(gender, '')) = 'female' THEN 'Female'
              ELSE 'Other'
            END AS gender,
            phone,
            email,
            category,
            role_title AS "roleTitle",
            teacher_uid AS "teacherUid"
          FROM school_contacts
          WHERE contact_id = $1
          LIMIT 1
        `,
        [contactId],
      );
      const contact = contactResult.rows[0];
      if (!contact) {
        throw new Error("Contact not found.");
      }

      /* ── Load training record ──────────────────────────────────── */
      const trainingResult = await client.query<{
        id: number;
        recordCode: string;
        payloadJson: string;
      }>(
        `
          SELECT
            id,
            record_code AS "recordCode",
            COALESCE(payload_json, '{}') AS "payloadJson"
          FROM portal_records
          WHERE id = $1
            AND module = 'training'
            AND deleted_at IS NULL
          LIMIT 1
        `,
        [trainingRecordId],
      );
      const training = trainingResult.rows[0];
      if (!training) {
        throw new Error("Training session not found.");
      }

      /* ── Load school ───────────────────────────────────────────── */
      const schoolResult = await client.query<{
        id: number;
        name: string;
        region: string;
        district: string;
      }>(
        `
          SELECT
            id,
            name,
            COALESCE(region, '') AS region,
            COALESCE(district, '') AS district
          FROM schools_directory
          WHERE id = $1
          LIMIT 1
        `,
        [contact.schoolId],
      );
      const school = schoolResult.rows[0];
      if (!school) {
        throw new Error("School for contact not found.");
      }

      /* ── Check for existing registration ───────────────────────── */
      const existingResult = await client.query<{ id: number }>(
        `
          SELECT id
          FROM portal_training_attendance
          WHERE portal_record_id = $1
            AND contact_id = $2
          LIMIT 1
        `,
        [trainingRecordId, contactId],
      );
      if (existingResult.rows[0]) {
        await client.query("ROLLBACK");
        return { action: "ALREADY_REGISTERED" as const, trainingRecordId, contactId };
      }

      /* ── Determine role ────────────────────────────────────────── */
      const categoryLower = (contact.category ?? "").toLowerCase();
      const roleTitleLower = (contact.roleTitle ?? "").toLowerCase();
      const isLeader =
        categoryLower.includes("head teacher") ||
        categoryLower.includes("deputy") ||
        categoryLower.includes("proprietor") ||
        categoryLower.includes("dos") ||
        categoryLower.includes("administrator") ||
        roleTitleLower.includes("leader") ||
        roleTitleLower.includes("head");
      const participantRole = isLeader ? "School Leader" : "Classroom teacher";

      /* ── Insert attendance record ──────────────────────────────── */
      const participantCode = `TP-${trainingRecordId}-${contactId}`;
      await client.query(
        `
          INSERT INTO portal_training_attendance (
            portal_record_id,
            school_id,
            contact_id,
            contact_uid,
            participant_code,
            participant_name,
            participant_role,
            participant_type,
            invited,
            confirmed,
            role_at_time,
            gender,
            teacher_uid,
            attended,
            phone,
            email,
            mobile_number,
            school_name_snapshot,
            school_region_snapshot,
            school_district_snapshot,
            attendance_status,
            certificate_status,
            notes,
            created_at,
            updated_at
          ) VALUES (
            $1, $2, $3, $4, $5, $6, $7, 'In Person', TRUE, FALSE,
            $8, $9, $10, FALSE, $11, $12, $13, $14, $15, $16,
            'Registered', 'Pending', NULL, NOW(), NOW()
          )
        `,
        [
          trainingRecordId,
          school.id,
          contact.contactId,
          contact.contactUid,
          participantCode,
          contact.fullName,
          participantRole,
          participantRole,
          contact.gender,
          contact.teacherUid,
          contact.phone,
          contact.email,
          contact.phone,
          school.name,
          school.region,
          school.district,
        ],
      );

      /* ── Update training payload JSON participants array ─────── */
      let payload: Record<string, unknown>;
      try {
        payload = JSON.parse(training.payloadJson) as Record<string, unknown>;
      } catch {
        payload = {};
      }
      const participants = Array.isArray(payload.participants) ? payload.participants as Array<Record<string, unknown>> : [];
      participants.push({
        contactId: contact.contactId,
        contactUid: contact.contactUid,
        participantName: contact.fullName,
        schoolAccountId: school.id,
        schoolAttachedTo: school.name,
        role: isLeader ? "Leader" : "Teacher",
        gender: contact.gender,
        phoneContact: contact.phone ?? "",
        email: contact.email ?? "",
        participantType: "In Person",
        invited: true,
        confirmed: false,
        attended: false,
        attendanceStatus: "Registered",
        certificateStatus: "Pending",
      });
      payload.participants = participants;

      /* ── Update summary counts ─────────────────────────────────── */
      payload.classroomTeachers = participants.filter((p) => p.role === "Teacher").length;
      payload.schoolLeaders = participants.filter((p) => p.role === "Leader").length;

      await client.query(
        `
          UPDATE portal_records
          SET
            payload_json = $2,
            updated_by_user_id = $3,
            updated_at = NOW()
          WHERE id = $1
        `,
        [trainingRecordId, JSON.stringify(payload), actor.id],
      );

      /* ── Audit log ─────────────────────────────────────────────── */
      await client.query(
        `
          INSERT INTO audit_logs (
            user_id,
            user_name,
            action,
            target_table,
            target_id,
            payload_after,
            detail
          ) VALUES (
            $1, $2, $3, 'portal_training_attendance', $4, $5, $6
          )
        `,
        [
          actor.id,
          actor.fullName,
          "create",
          String(trainingRecordId),
          JSON.stringify({
            trainingRecordId,
            contactId,
            schoolId: school.id,
            attendanceStatus: "Registered",
          }),
          `Added training participant ${contact.fullName} from Contact Profile.`,
        ],
      );

      await client.query("COMMIT");
      return { action: "CREATED" as const, trainingRecordId, contactId };
    } catch (error) {
      await client.query("ROLLBACK");
      throw error;
    }
  });
}

export async function POST(request: Request) {
  const user = await getAuthenticatedPortalUser();
  return withRouteHandler({
    route: "/api/portal/contacts/add-to-training",
