        ...report,
        pdfUrl: report.pdfPath
          ? `/api/portal/national-intelligence/reports/${encodeURIComponent(report.reportCode)}/pdf`
          : null,
      },
    });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: error.issues[0]?.message ?? "Invalid national report payload." },
        { status: 400 },
      );
    }
    if (error instanceof Error) {
      return NextResponse.json({ error: error.message }, { status: 400 });
    }
    return NextResponse.json({ error: "Server error." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { z } from "zod";
import { updateOnlineTrainingSessionOutcomesPostgres } from "@/lib/server/postgres/repositories/training";
import { getAuthenticatedPortalUser } from "@/lib/auth";

export const runtime = "nodejs";

const updateSchema = z.object({
  onlineTeachersTrained: z.coerce.number().int().min(0),
  onlineSchoolLeadersTrained: z.coerce.number().int().min(0),
  attendeeCount: z.coerce.number().int().min(0).optional(),
  recordingUrl: z.string().trim().url().optional().or(z.literal("")),
  chatSummary: z.string().trim().max(5000).optional(),
});

function parseEventId(value: string) {
  const eventId = Number(value);
  if (!Number.isInteger(eventId) || eventId <= 0) {
    throw new Error("Invalid event ID.");
  }
  return eventId;
}

export async function GET(
  _request: Request,
  context: { params: Promise<{ id: string }> },
) {
  // Simple pass-through not normally used, leaving implemented but stubbed to avoid complex mapping unless necessary
  return NextResponse.json({ error: "Direct GET for individual sessions is deprecated." }, { status: 400 });
}

export async function PATCH(
  request: Request,
  context: { params: Promise<{ id: string }> },
) {
  const user = await getAuthenticatedPortalUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  if (user.role === "Volunteer") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  try {
    const { id } = await context.params;
    const eventId = parseEventId(id);
    const payload = updateSchema.parse(await request.json());

    await updateOnlineTrainingSessionOutcomesPostgres(eventId, {
      attendeeCount: payload.attendeeCount ?? 0,
      onlineTeachersTrained: payload.onlineTeachersTrained,
      onlineSchoolLeadersTrained: payload.onlineSchoolLeadersTrained,
      recordingUrl: payload.recordingUrl || null,
      chatSummary: payload.chatSummary || null,
      attendanceCapturedAt: new Date().toISOString()
    });

    const event = {
      id: eventId,
    };

    return NextResponse.json({ ok: true, event });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: error.issues[0]?.message ?? "Invalid update payload." },
        { status: 400 },
      );
    }
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "Server error." },
      { status: 400 },
    );
  }
}

