                      </div>
                      <h2 className="text-3xl md:text-4xl font-extrabold text-brand-primary mb-4 leading-tight">
                        <Link href={`/blog/${featured.slug}`} className="hover:text-brand-primary transition-colors">
                          {featured.title}
