  { src: "/photos/11.jpeg", alt: "Facilitator leading phonics instruction with participants." },
  { src: "/photos/12.jpeg", alt: "Teacher collaboration during classroom practice planning." },
  { src: "/photos/13.jpeg", alt: "School-based coaching conversation with literacy mentors." },
  { src: "/photos/14.jpeg", alt: "Participants reviewing reading assessment tools." },
  { src: "/photos/15.jpeg", alt: "Training group engagement in practical lesson routines." },
  { src: "/photos/16.jpeg", alt: "Teachers working through phonics implementation steps." },
  { src: "/photos/17.jpeg", alt: "District-level literacy support and planning moment." },
  { src: "/photos/18.jpeg", alt: "Active school support visit documenting reading routines." },
  { src: "/photos/19.jpeg", alt: "Teachers sharing outcomes from classroom implementation." },
  { src: "/photos/20.jpeg", alt: "Reading lesson facilitation in a school environment." },
  { src: "/photos/21.jpeg", alt: "Educators in an interactive training reflection segment." },
];

function chunkIntoSlides<T>(items: T[], chunkSize: number): T[][] {
  const chunks: T[][] = [];
  for (let index = 0; index < items.length; index += chunkSize) {
    chunks.push(items.slice(index, index + chunkSize));
  }
  return chunks;
}

export function PublicGalleryShowcase() {
  const slides = useMemo(() => chunkIntoSlides(GALLERY_IMAGES, 3), []);
  const [activeSlide, setActiveSlide] = useState(0);

  useEffect(() => {
    if (slides.length <= 1) {
      return;
    }
    const timer = window.setInterval(() => {
      setActiveSlide((current) => (current + 1) % slides.length);
    }, 5500);
    return () => window.clearInterval(timer);
  }, [slides.length]);

  return (
    <section className="section">
      <div className="container">
        <article className="gallery-showcase-shell">
          <div className="gallery-showcase-head">
            <p className="gallery-showcase-kicker">Gallery</p>
            <h1>Moments From Our Literacy Field Work</h1>
            <p>
              Photos from trainings, coaching visits, and school support sessions across districts.
            </p>
          </div>

          <div className="gallery-showcase-stage">
            <AnimatePresence mode="wait">
              <motion.div
                key={`gallery-slide-${activeSlide}`}
                className="gallery-showcase-grid"
                initial={{ opacity: 0, y: 18 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -16 }}
                transition={{ duration: 0.35, ease: [0.22, 1, 0.36, 1] }}
              >
                {slides[activeSlide]?.map((image) => (
                  <figure className="gallery-showcase-card" key={image.src}>
                    <img src={image.src} alt={image.alt} loading="lazy" decoding="async" />
                  </figure>
                ))}
              </motion.div>
            </AnimatePresence>
          </div>

          <div className="gallery-showcase-dots" aria-label="Gallery pagination">
            {slides.map((_, index) => (
              <button
                key={`gallery-dot-${index + 1}`}
                type="button"
                className={index === activeSlide ? "is-active" : ""}
                onClick={() => setActiveSlide(index)}
                aria-label={`Open gallery slide ${index + 1}`}
                aria-current={index === activeSlide ? "true" : "false"}
              />
            ))}
          </div>

          <div className="gallery-showcase-actions">
            <Link className="button button-accent" href="/partner-with-us">
              Partner With Us
            </Link>
            <Link className="button" href="/impact/gallery">
              Open Evidence Gallery
            </Link>
          </div>
        </article>
      </div>
    </section>
  );
}

"use client";

import { ChangeEvent, FormEvent, useMemo, useState } from "react";
import {
  AboutTeamSection,
  PortalCoreValueRecord,
  PortalLeadershipTeamMemberRecord,
} from "@/lib/types";

type LeadershipMemberView = PortalLeadershipTeamMemberRecord & {
  photoUrl: string | null;
};

type PortalAboutContentManagerProps = {
  initialMembers: LeadershipMemberView[];
  initialValues: PortalCoreValueRecord[];
};

type FeedbackState = {
  kind: "idle" | "success" | "error";
  message: string;
};

type LeadershipFormState = {
  id: number | null;
  section: AboutTeamSection;
  name: string;
  role: string;
  biography: string;
  background: string;
  career: string;
  photoAlt: string;
  sortOrder: number;
  isPublished: boolean;
  removePhoto: boolean;
};

type CoreValueFormState = {
  id: number | null;
  title: string;
  description: string;
  sortOrder: number;
  isPublished: boolean;
};

const sectionCopy: Record<
  AboutTeamSection,
  { kicker: string; title: string }
> = {
  board: { kicker: "Board Members", title: "Board Governance" },
  staff: { kicker: "Staff", title: "Core Staff Team" },
  volunteer: { kicker: "Volunteers", title: "Volunteer Team" },
};

const defaultLeadershipForm: LeadershipFormState = {
  id: null,
  section: "board",
  name: "",
  role: "",
  biography: "",
  background: "",
  career: "",
  photoAlt: "",
  sortOrder: 0,
  isPublished: true,
  removePhoto: false,
};

const defaultCoreValueForm: CoreValueFormState = {
  id: null,
  title: "",
  description: "",
  sortOrder: 0,
  isPublished: true,
};

function sortMembers(items: LeadershipMemberView[]) {
  const sectionOrder: Record<AboutTeamSection, number> = {
    board: 1,
    staff: 2,
    volunteer: 3,
  };
  return [...items].sort((left, right) => {
    const sectionDelta = sectionOrder[left.section] - sectionOrder[right.section];
    if (sectionDelta !== 0) {
      return sectionDelta;
    }
    if (left.sortOrder !== right.sortOrder) {
      return left.sortOrder - right.sortOrder;
    }
    return right.updatedAt.localeCompare(left.updatedAt);
  });
}

function sortValues(items: PortalCoreValueRecord[]) {
  return [...items].sort((left, right) => {
    if (left.sortOrder !== right.sortOrder) {
      return left.sortOrder - right.sortOrder;
    }
    return right.updatedAt.localeCompare(left.updatedAt);
  });
}

export function PortalAboutContentManager({
  initialMembers,
  initialValues,
}: PortalAboutContentManagerProps) {
  const [members, setMembers] = useState<LeadershipMemberView[]>(() =>
    sortMembers(initialMembers),
  );
  const [coreValues, setCoreValues] = useState<PortalCoreValueRecord[]>(() =>
    sortValues(initialValues),
  );
  const [leadershipForm, setLeadershipForm] =
    useState<LeadershipFormState>(defaultLeadershipForm);
  const [coreValueForm, setCoreValueForm] =
    useState<CoreValueFormState>(defaultCoreValueForm);
  const [photoFile, setPhotoFile] = useState<File | null>(null);
  const [savingLeadership, setSavingLeadership] = useState(false);
  const [savingCoreValue, setSavingCoreValue] = useState(false);
  const [feedback, setFeedback] = useState<FeedbackState>({
    kind: "idle",
    message: "",
  });
  const [formKey, setFormKey] = useState(0);

  const membersBySection = useMemo(() => {
    return {
      board: members.filter((item) => item.section === "board"),
      staff: members.filter((item) => item.section === "staff"),
      volunteer: members.filter((item) => item.section === "volunteer"),
    };
  }, [members]);

  function resetLeadershipForm() {
    setLeadershipForm(defaultLeadershipForm);
    setPhotoFile(null);
    setFormKey((prev) => prev + 1);
  }

  function resetCoreValueForm() {
    setCoreValueForm(defaultCoreValueForm);
  }

  function handleLeadershipChange(
    field: keyof LeadershipFormState,
    value: string | number | boolean,
  ) {
    setLeadershipForm((prev) => ({ ...prev, [field]: value }));
  }

  function handleCoreValueChange(
    field: keyof CoreValueFormState,
    value: string | number | boolean,
  ) {
    setCoreValueForm((prev) => ({ ...prev, [field]: value }));
  }

  function beginEditMember(member: LeadershipMemberView) {
    setLeadershipForm({
      id: member.id,
      section: member.section,
      name: member.name,
      role: member.role,
      biography: member.biography,
      background: member.background,
      career: member.career,
      photoAlt: member.photoAlt ?? "",
      sortOrder: member.sortOrder,
      isPublished: member.isPublished,
      removePhoto: false,
    });
    setPhotoFile(null);
    setFormKey((prev) => prev + 1);
  }

  function beginEditCoreValue(value: PortalCoreValueRecord) {
    setCoreValueForm({
      id: value.id,
      title: value.title,
      description: value.description,
      sortOrder: value.sortOrder,
      isPublished: value.isPublished,
    });
  }

  async function handleLeadershipSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setSavingLeadership(true);
    setFeedback({ kind: "idle", message: "" });
    try {
      const formData = new FormData();
      if (leadershipForm.id) {
        formData.set("id", String(leadershipForm.id));
      }
      formData.set("section", leadershipForm.section);
      formData.set("name", leadershipForm.name);
      formData.set("role", leadershipForm.role);
      formData.set("biography", leadershipForm.biography);
      formData.set("background", leadershipForm.background);
      formData.set("career", leadershipForm.career);
      formData.set("photoAlt", leadershipForm.photoAlt);
      formData.set("sortOrder", String(leadershipForm.sortOrder));
      formData.set("isPublished", leadershipForm.isPublished ? "1" : "0");
      formData.set("removePhoto", leadershipForm.removePhoto ? "1" : "0");
      if (photoFile) {
        formData.set("photo", photoFile);
      }

      const response = await fetch("/api/portal/about/team", {
        method: leadershipForm.id ? "PATCH" : "POST",
        body: formData,
      });
      const data = (await response.json()) as {
        error?: string;
        member?: LeadershipMemberView;
      };
      if (!response.ok || !data.member) {
        throw new Error(data.error ?? "Could not save leadership team member.");
      }
      setMembers((prev) => {
        const next = leadershipForm.id
          ? prev.map((item) => (item.id === data.member!.id ? data.member! : item))
          : [data.member!, ...prev];
        return sortMembers(next);
      });
      setFeedback({
        kind: "success",
        message: leadershipForm.id
          ? "Leadership team member updated."
          : "Leadership team member created.",
      });
      resetLeadershipForm();
    } catch (error) {
      setFeedback({
        kind: "error",
        message:
          error instanceof Error
            ? error.message
            : "Could not save leadership team member.",
      });
    } finally {
      setSavingLeadership(false);
    }
  }

  async function handleMemberPublishToggle(member: LeadershipMemberView) {
    setFeedback({ kind: "idle", message: "" });
    try {
      const formData = new FormData();
      formData.set("id", String(member.id));
      formData.set("section", member.section);
      formData.set("name", member.name);
      formData.set("role", member.role);
      formData.set("biography", member.biography);
      formData.set("background", member.background);
      formData.set("career", member.career);
      formData.set("photoAlt", member.photoAlt ?? "");
      formData.set("sortOrder", String(member.sortOrder));
      formData.set("isPublished", member.isPublished ? "0" : "1");
      const response = await fetch("/api/portal/about/team", {
        method: "PATCH",
        body: formData,
      });
      const data = (await response.json()) as {
        error?: string;
        member?: LeadershipMemberView;
      };
      if (!response.ok || !data.member) {
        throw new Error(data.error ?? "Could not update publish state.");
      }
      setMembers((prev) =>
        sortMembers(prev.map((item) => (item.id === data.member!.id ? data.member! : item))),
      );
    } catch (error) {
      setFeedback({
        kind: "error",
        message:
          error instanceof Error ? error.message : "Could not update publish state.",
      });
    }
  }

  async function handleMemberDelete(member: LeadershipMemberView) {
    if (!window.confirm(`Delete ${member.name}? This cannot be undone.`)) {
      return;
    }
    setFeedback({ kind: "idle", message: "" });
    try {
      const response = await fetch("/api/portal/about/team", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: member.id }),
      });
      const data = (await response.json()) as { error?: string };
      if (!response.ok) {
        throw new Error(data.error ?? "Could not delete leadership team member.");
      }
      setMembers((prev) => prev.filter((item) => item.id !== member.id));
      if (leadershipForm.id === member.id) {
        resetLeadershipForm();
      }
    } catch (error) {
      setFeedback({
        kind: "error",
        message:
          error instanceof Error
            ? error.message
            : "Could not delete leadership team member.",
      });
    }
  }

  async function handleCoreValueSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setSavingCoreValue(true);
    setFeedback({ kind: "idle", message: "" });
    try {
      const response = await fetch("/api/portal/about/core-values", {
        method: coreValueForm.id ? "PATCH" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(coreValueForm),
      });
      const data = (await response.json()) as {
        error?: string;
        value?: PortalCoreValueRecord;
      };
      if (!response.ok || !data.value) {
        throw new Error(data.error ?? "Could not save core value.");
      }
      setCoreValues((prev) => {
        const next = coreValueForm.id
          ? prev.map((item) => (item.id === data.value!.id ? data.value! : item))
          : [data.value!, ...prev];
        return sortValues(next);
      });
      setFeedback({
        kind: "success",
        message: coreValueForm.id ? "Core value updated." : "Core value created.",
      });
      resetCoreValueForm();
    } catch (error) {
      setFeedback({
        kind: "error",
        message: error instanceof Error ? error.message : "Could not save core value.",
      });
    } finally {
      setSavingCoreValue(false);
    }
  }

  async function handleCoreValuePublishToggle(value: PortalCoreValueRecord) {
    setFeedback({ kind: "idle", message: "" });
    try {
      const response = await fetch("/api/portal/about/core-values", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          id: value.id,
          title: value.title,
          description: value.description,
          sortOrder: value.sortOrder,
          isPublished: !value.isPublished,
        }),
      });
      const data = (await response.json()) as {
        error?: string;
        value?: PortalCoreValueRecord;
      };
      if (!response.ok || !data.value) {
        throw new Error(data.error ?? "Could not update core value state.");
      }
      setCoreValues((prev) =>
        sortValues(prev.map((item) => (item.id === data.value!.id ? data.value! : item))),
      );
    } catch (error) {
      setFeedback({
        kind: "error",
        message:
          error instanceof Error
            ? error.message
            : "Could not update core value state.",
      });
    }
  }

  async function handleCoreValueDelete(value: PortalCoreValueRecord) {
    if (!window.confirm(`Delete "${value.title}"? This cannot be undone.`)) {
      return;
    }
    setFeedback({ kind: "idle", message: "" });
    try {
      const response = await fetch("/api/portal/about/core-values", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: value.id }),
      });
      const data = (await response.json()) as { error?: string };
      if (!response.ok) {
        throw new Error(data.error ?? "Could not delete core value.");
      }
      setCoreValues((prev) => prev.filter((item) => item.id !== value.id));
      if (coreValueForm.id === value.id) {
        resetCoreValueForm();
      }
    } catch (error) {
      setFeedback({
        kind: "error",
        message: error instanceof Error ? error.message : "Could not delete core value.",
      });
    }
  }

  return (
    <div className="portal-grid">
      <section className="card">
        <h2>Leadership Team</h2>
        <p>
          Add board, staff, and volunteer profiles exactly as they appear on the public
          leadership page. Unpublished records stay hidden from the public site.
        </p>
        {feedback.message ? (
          <p
            role="status"
            className={`form-message ${
              feedback.kind === "error" ? "error" : "success"
            }`}
          >
            {feedback.message}
          </p>
        ) : null}

        <form
          key={formKey}
          onSubmit={(event) => void handleLeadershipSubmit(event)}
          style={{ display: "grid", gap: "0.9rem", marginTop: "1rem" }}
        >
          <div style={{ display: "grid", gap: "0.9rem", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))" }}>
            <label>
              Section
              <select
                value={leadershipForm.section}
                onChange={(event) =>
                  handleLeadershipChange("section", event.target.value as AboutTeamSection)
                }
              >
                <option value="board">Board</option>
                <option value="staff">Staff</option>
                <option value="volunteer">Volunteer</option>
              </select>
            </label>
            <label>
              Sort order
              <input
                type="number"
                min={0}
                value={leadershipForm.sortOrder}
                onChange={(event) =>
                  handleLeadershipChange("sortOrder", Number(event.target.value || 0))
                }
              />
            </label>
            <label>
              Publish now
              <select
                value={leadershipForm.isPublished ? "yes" : "no"}
                onChange={(event) =>
                  handleLeadershipChange("isPublished", event.target.value === "yes")
                }
              >
                <option value="yes">Published</option>
                <option value="no">Draft</option>
              </select>
            </label>
          </div>

          <div style={{ display: "grid", gap: "0.9rem", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))" }}>
            <label>
              Name
              <input
                type="text"
                value={leadershipForm.name}
                onChange={(event) => handleLeadershipChange("name", event.target.value)}
              />
            </label>
            <label>
              Role
              <input
                type="text"
                value={leadershipForm.role}
                onChange={(event) => handleLeadershipChange("role", event.target.value)}
              />
            </label>
          </div>

          <label>
            Biography
            <textarea
              rows={4}
              value={leadershipForm.biography}
              onChange={(event) => handleLeadershipChange("biography", event.target.value)}
            />
          </label>

          <label>
            Background
            <textarea
              rows={3}
              value={leadershipForm.background}
              onChange={(event) => handleLeadershipChange("background", event.target.value)}
            />
          </label>

          <label>
            Career
            <textarea
              rows={3}
              value={leadershipForm.career}
              onChange={(event) => handleLeadershipChange("career", event.target.value)}
            />
          </label>

          <div style={{ display: "grid", gap: "0.9rem", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))" }}>
            <label>
              Profile photo
              <input
                type="file"
                accept=".jpg,.jpeg,.png,.webp,.avif"
                onChange={(event: ChangeEvent<HTMLInputElement>) =>
                  setPhotoFile(event.target.files?.[0] ?? null)
                }
              />
            </label>
            <label>
              Photo alt text
              <input
                type="text"
                value={leadershipForm.photoAlt}
                onChange={(event) => handleLeadershipChange("photoAlt", event.target.value)}
              />
            </label>
          </div>

          {leadershipForm.id ? (
            <label style={{ display: "inline-flex", alignItems: "center", gap: "0.45rem" }}>
              <input
                type="checkbox"
                checked={leadershipForm.removePhoto}
                onChange={(event) =>
                  handleLeadershipChange("removePhoto", event.target.checked)
                }
              />
              Remove current profile photo
            </label>
          ) : null}

          <div className="action-row">
            <button className="button" type="submit" disabled={savingLeadership}>
              {savingLeadership
                ? "Saving..."
                : leadershipForm.id
                  ? "Update team member"
                  : "Add team member"}
            </button>
            {leadershipForm.id ? (
              <button
                className="button button-ghost"
                type="button"
                onClick={resetLeadershipForm}
              >
                Cancel edit
              </button>
            ) : null}
          </div>
        </form>
      </section>

      <section className="card">
        <h2>Current Leadership Profiles</h2>
        {members.length === 0 ? (
          <p>No leadership profiles have been added yet.</p>
        ) : (
          <div style={{ display: "grid", gap: "1rem" }}>
            {(["board", "staff", "volunteer"] as AboutTeamSection[]).map((section) => (
              <div key={section} style={{ display: "grid", gap: "0.75rem" }}>
                <div>
                  <p className="kicker">{sectionCopy[section].kicker}</p>
                  <h3 style={{ margin: 0 }}>{sectionCopy[section].title}</h3>
                </div>
                {membersBySection[section].length === 0 ? (
                  <p className="portal-muted">No profiles in this section yet.</p>
                ) : (
                  membersBySection[section].map((member) => (
                    <article
                      key={member.id}
                      className="card"
                      style={{
                        display: "grid",
                        gap: "0.9rem",
                        gridTemplateColumns: "160px minmax(0, 1fr)",
                      }}
                    >
                      <div>
                        {member.photoUrl ? (
                          <img
                            src={member.photoUrl}
                            alt={member.photoAlt || member.name}
                            style={{
                              width: "100%",
                              aspectRatio: "4 / 3",
                              borderRadius: "12px",
                              objectFit: "cover",
                              display: "block",
                            }}
                          />
                        ) : (
                          <div
                            style={{
                              width: "100%",
                              aspectRatio: "4 / 3",
                              borderRadius: "12px",
                              display: "grid",
                              placeItems: "center",
                              background:
                                "linear-gradient(135deg, var(--color-brand-blue), #101828)",
                              color: "#fff",
                              fontWeight: 700,
                              letterSpacing: "0.08em",
                            }}
                          >
                            {member.name
                              .split(" ")
                              .filter(Boolean)
                              .slice(0, 2)
                              .map((part) => part[0]?.toUpperCase() ?? "")
                              .join("")}
                          </div>
                        )}
                      </div>
                      <div style={{ display: "grid", gap: "0.45rem" }}>
                        <div style={{ display: "flex", gap: "0.6rem", flexWrap: "wrap", alignItems: "center" }}>
                          <h3 style={{ margin: 0 }}>{member.name}</h3>
                          <span className="meta-pill">
                            {member.isPublished ? "Published" : "Draft"}
                          </span>
                        </div>
                        <p style={{ margin: 0, color: "var(--md-sys-color-on-surface-variant)", fontWeight: 600 }}>
                          {member.role}
                        </p>
                        <p style={{ margin: 0 }}>{member.biography}</p>
                        <p style={{ margin: 0 }}>
                          <strong>Background:</strong> {member.background}
                        </p>
                        <p style={{ margin: 0 }}>
                          <strong>Career:</strong> {member.career}
                        </p>
                        <div className="action-row">
                          <button
                            className="button button-ghost"
                            type="button"
                            onClick={() => beginEditMember(member)}
                          >
                            Edit
                          </button>
                          <button
                            className="button button-ghost"
                            type="button"
                            onClick={() => void handleMemberPublishToggle(member)}
                          >
                            {member.isPublished ? "Unpublish" : "Publish"}
                          </button>
                          <button
                            className="button button-ghost"
                            type="button"
                            onClick={() => void handleMemberDelete(member)}
                          >
                            Delete
                          </button>
                        </div>
                      </div>
                    </article>
                  ))
                )}
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="card">
        <h2>Core Values</h2>
        <p>
          Add each public core value with only the title and description. These render as
          full-width cards on the About page.
        </p>
        <form
          onSubmit={(event) => void handleCoreValueSubmit(event)}
          style={{ display: "grid", gap: "0.9rem", marginTop: "1rem" }}
        >
          <div style={{ display: "grid", gap: "0.9rem", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))" }}>
            <label>
              Title
              <input
                type="text"
                value={coreValueForm.title}
                onChange={(event) => handleCoreValueChange("title", event.target.value)}
              />
            </label>
            <label>
              Sort order
              <input
                type="number"
                min={0}
                value={coreValueForm.sortOrder}
                onChange={(event) =>
                  handleCoreValueChange("sortOrder", Number(event.target.value || 0))
                }
              />
            </label>
            <label>
              Publish now
              <select
                value={coreValueForm.isPublished ? "yes" : "no"}
                onChange={(event) =>
                  handleCoreValueChange("isPublished", event.target.value === "yes")
                }
              >
                <option value="yes">Published</option>
                <option value="no">Draft</option>
              </select>
            </label>
          </div>
          <label>
            Description
            <textarea
              rows={5}
              value={coreValueForm.description}
              onChange={(event) =>
                handleCoreValueChange("description", event.target.value)
              }
            />
          </label>
          <div className="action-row">
            <button className="button" type="submit" disabled={savingCoreValue}>
              {savingCoreValue
                ? "Saving..."
                : coreValueForm.id
                  ? "Update core value"
                  : "Add core value"}
            </button>
            {coreValueForm.id ? (
              <button
                className="button button-ghost"
                type="button"
                onClick={resetCoreValueForm}
              >
                Cancel edit
              </button>
            ) : null}
          </div>
        </form>
      </section>

      <section className="card">
        <h2>Current Core Values</h2>
        {coreValues.length === 0 ? (
          <p>No core values have been added yet.</p>
        ) : (
          <div style={{ display: "grid", gap: "0.9rem" }}>
            {coreValues.map((value) => (
              <article className="card" key={value.id}>
                <div style={{ display: "flex", gap: "0.6rem", flexWrap: "wrap", alignItems: "center" }}>
                  <h3 style={{ margin: 0 }}>{value.title}</h3>
                  <span className="meta-pill">
                    {value.isPublished ? "Published" : "Draft"}
                  </span>
                </div>
                <p style={{ marginTop: "0.65rem", marginBottom: 0 }}>{value.description}</p>
                <div className="action-row" style={{ marginTop: "0.85rem" }}>
                  <button
                    className="button button-ghost"
                    type="button"
                    onClick={() => beginEditCoreValue(value)}
                  >
                    Edit
                  </button>
                  <button
                    className="button button-ghost"
                    type="button"
                    onClick={() => void handleCoreValuePublishToggle(value)}
                  >
                    {value.isPublished ? "Unpublish" : "Publish"}
                  </button>
                  <button
                    className="button button-ghost"
                    type="button"
                    onClick={() => void handleCoreValueDelete(value)}
                  >
                    Delete
                  </button>
                </div>
              </article>
            ))}
          </div>
        )}
      </section>
    </div>
  );
}

"use client";

import { FormEvent, useMemo, useState } from "react";
import { PortalTestimonialRecord } from "@/lib/types";
import { buildVideoThumbnailFallback } from "@/lib/media-placeholders";
import { FloatingSurface } from "@/components/FloatingSurface";

type PortalTestimonialView = PortalTestimonialRecord & {
  videoUrl: string;
  photoUrl: string | null;
};

interface PortalTestimonialsManagerProps {
  initialTestimonials: PortalTestimonialView[];
  canModerate: boolean;
  schoolOptions: Array<{
    id: number;
    name: string;
    district: string;
    region: string;
    subRegion: string;
  }>;
  defaultSchoolId?: number | null;
}

type FeedbackState = {
  kind: "idle" | "success" | "error";
  message: string;
};

function formatDate(value: string) {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) {
    return value;
  }
  return new Intl.DateTimeFormat("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
    timeZone: "UTC",
  }).format(parsed);
}

export function PortalTestimonialsManager({
  initialTestimonials,
  canModerate,
  schoolOptions,
  defaultSchoolId = null,
}: PortalTestimonialsManagerProps) {
  const [testimonials, setTestimonials] = useState(initialTestimonials);
  const [selectedSchoolId, setSelectedSchoolId] = useState<number | null>(() => {
    if (defaultSchoolId && schoolOptions.some((item) => item.id === defaultSchoolId)) {
      return defaultSchoolId;
    }
    return null;
  });
  const [saving, setSaving] = useState(false);
  const [feedback, setFeedback] = useState<FeedbackState>({
    kind: "idle",
    message: "",
  });
  const [selectedVideo, setSelectedVideo] = useState<File | null>(null);
  const [selectedPhoto, setSelectedPhoto] = useState<File | null>(null);
  const [playingVideoIds, setPlayingVideoIds] = useState<Record<number, boolean>>({});
  const [formKey, setFormKey] = useState(0);
  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const selectedSchool = useMemo(
    () => schoolOptions.find((item) => item.id === selectedSchoolId) ?? null,
    [schoolOptions, selectedSchoolId],
  );

  async function handleModeration(
    testimonialId: number,
    moderationStatus: "pending" | "approved" | "hidden",
  ) {
    try {
      const response = await fetch("/api/portal/testimonials", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ testimonialId, moderationStatus }),
      });
      const data = (await response.json()) as { error?: string; testimonial?: PortalTestimonialView };
      if (!response.ok || !data.testimonial) {
        throw new Error(data.error ?? "Could not update testimonial moderation status.");
      }
      setTestimonials((prev) =>
        prev.map((item) => (item.id === testimonialId ? data.testimonial as PortalTestimonialView : item)),
      );
      setFeedback({
        kind: "success",
        message: `Testimonial moderation set to ${moderationStatus}.`,
      });
    } catch (error) {
      setFeedback({
        kind: "error",
        message: error instanceof Error ? error.message : "Could not update moderation status.",
      });
    }
  }

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setSaving(true);
    setFeedback({ kind: "success", message: "Publishing change story..." });

    const formData = new FormData(event.currentTarget);
    if (!selectedSchoolId || !selectedSchool) {
      setFeedback({ kind: "error", message: "Please select a school profile." });
      setSaving(false);
      return;
    }
    formData.set("schoolId", String(selectedSchoolId));

    try {
      const response = await fetch("/api/portal/testimonials", {
        method: "POST",
        body: formData,
      });
      const data = (await response.json()) as {
        error?: string;
        testimonial?: PortalTestimonialView;
      };

      if (!response.ok || !data.testimonial) {
        throw new Error(data.error ?? "Could not submit change story.");
      }

      setTestimonials((prev) => [data.testimonial as PortalTestimonialView, ...prev]);
      event.currentTarget.reset();
      setFormKey((prev) => prev + 1);
      setSelectedSchoolId(defaultSchoolId ?? null);
      setSelectedVideo(null);
      setSelectedPhoto(null);
      setPlayingVideoIds({});
      setFeedback({
        kind: "success",
        message: "Change story submitted and published successfully.",
      });
      setIsCreateOpen(false);
    } catch (error) {
      const fallback = "Could not submit change story.";
      setFeedback({
        kind: "error",
        message: error instanceof Error ? error.message : fallback,
      });
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="portal-grid">
      <section className="card">
        <h2>Submit Change Story</h2>
        <p>
          Staff and volunteers can capture measurable change stories with photo evidence.
          Approved submissions appear automatically in the public stories of measurable change pages.
        </p>
        <div className="action-row portal-form-actions">
          <button className="button" type="button" onClick={() => setIsCreateOpen(true)}>
            + New Change Story
          </button>
        </div>
        {feedback.message ? (
          <p
            role="status"
            className={`form-message ${feedback.kind === "error" ? "error" : "success"}`}
          >
            {feedback.message}
          </p>
        ) : null}
      </section>

      <section className="card">
        <h2>Recent Change Story Submissions</h2>
        {testimonials.length === 0 ? (
          <p>No change story submissions yet.</p>
        ) : (
          <div className="media-showcase-grid">
            {testimonials.map((item) => (
              <article className="card media-showcase-card video" key={item.id}>
                <div className="media-showcase-asset">
                  {item.photoUrl ? (
                    <img
                      src={item.photoUrl}
                      alt={`Testimonial by ${item.storytellerName}`}
                      loading="lazy"
                      decoding="async"
                    />
                  ) : item.videoSourceType === "youtube" &&
                    item.youtubeEmbedUrl ? (
                    playingVideoIds[item.id] ? (
                      <iframe
                        src={`${item.youtubeEmbedUrl}${item.youtubeEmbedUrl.includes("?") ? "&" : "?"}autoplay=1&rel=0&modestbranding=1`}
                        title={item.youtubeVideoTitle ?? `Testimonial video by ${item.storytellerName}`}
                        loading="lazy"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                        allowFullScreen
                      />
                    ) : (
                      <button
                        type="button"
                        className="media-showcase-thumbnail-button"
                        onClick={() =>
                          setPlayingVideoIds((prev) => ({ ...prev, [item.id]: true }))
                        }
                        aria-label={`Play testimonial video by ${item.storytellerName}`}
                      >
                        <img
                          src={
                            item.youtubeThumbnailUrl ||
                            (item.youtubeVideoId
                              ? `https://img.youtube.com/vi/${item.youtubeVideoId}/hqdefault.jpg`
                              : buildVideoThumbnailFallback(`portal-testimonial-${item.id}`, "Video thumbnail unavailable"))
                          }
                          alt={item.youtubeVideoTitle ?? `Testimonial video by ${item.storytellerName}`}
                          loading="lazy"
                          decoding="async"
                        />
                        <span className="media-showcase-play-overlay">
                          <svg width="16" height="12" viewBox="0 0 24 24" fill="none" aria-hidden>
                            <path
                              d="M23 7.5A4.5 4.5 0 0 0 19.5 4C16.7 3.5 12 3.5 12 3.5s-4.7 0-7.5.5A4.5 4.5 0 0 0 1 7.5 47 47 0 0 0 .5 12 47 47 0 0 0 1 16.5 4.5 4.5 0 0 0 4.5 20c2.8.5 7.5.5 7.5.5s4.7 0 7.5-.5a4.5 4.5 0 0 0 3.5-3.5A47 47 0 0 0 23.5 12 47 47 0 0 0 23 7.5Z"
                              fill="#FF0000"
                            />
                            <path d="M10 15.5V8.5L16.25 12L10 15.5Z" fill="#fff" />
                          </svg>
                          YouTube
                        </span>
                      </button>
                    )
                  ) : (
                    <div className="media-showcase-missing-video">
                      <p>Linked YouTube video metadata is missing for this entry.</p>
                    </div>
                  )}
                </div>
                <div className="media-showcase-content">
                  <p className="meta-pill">Change story</p>
                  <p className="media-showcase-quote">"{item.storyText}"</p>
                  <p className="media-showcase-meta">
                    <strong>{item.storytellerName}</strong> · {item.storytellerRole}
                  </p>
                  <p className="media-showcase-caption">
                    {item.schoolName}, {item.district} · {formatDate(item.createdAt)}
                  </p>
                  <p className="meta-line">
                    Moderation: <strong>{item.moderationStatus}</strong>
                  </p>
                  {item.sourceType === "training_feedback" ? (
                    <p className="meta-line">Auto-generated from structured training feedback.</p>
                  ) : null}
                  {canModerate ? (
                    <div className="action-row">
                      <button
                        className="button button-ghost"
                        type="button"
                        onClick={() => void handleModeration(item.id, "pending")}
                      >
                        Mark pending
                      </button>
                      <button
                        className="button button-ghost"
                        type="button"
                        onClick={() => void handleModeration(item.id, "approved")}
                      >
                        Approve
                      </button>
                      <button
                        className="button button-ghost"
                        type="button"
                        onClick={() => void handleModeration(item.id, "hidden")}
                      >
                        Hide
                      </button>
                    </div>
                  ) : null}
                  {item.videoSourceType === "youtube" && item.youtubeWatchUrl ? (
                    <a className="button button-ghost" href={item.youtubeWatchUrl} target="_blank" rel="noreferrer">
                      Open source
                    </a>
                  ) : (
                    <span className="meta-line">Set a YouTube title to link this video.</span>
                  )}
                </div>
              </article>
            ))}
          </div>
        )}
      </section>

      <FloatingSurface
        open={isCreateOpen}
        onClose={() => setIsCreateOpen(false)}
        title="Submit Change Story"
        description="Capture baseline challenge, what happened, and measurable change from the field."
        closeLabel="Close"
        maxWidth="980px"
      >
        <form
          key={formKey}
          className="form-grid portal-form-grid portal-testimonial-form"
          onSubmit={handleSubmit}
        >
          <label>
            <span className="portal-field-label">
              <span>Storyteller Name</span>
              <span className="portal-required-indicator">
                *<span className="visually-hidden">required</span>
              </span>
            </span>
            <input
              name="storytellerName"
              required
              minLength={2}
              placeholder="e.g. Esther Namusoke"
              autoComplete="name"
            />
          </label>
          <label>
            <span className="portal-field-label">
              <span>Storyteller Role</span>
              <span className="portal-required-indicator">
                *<span className="visually-hidden">required</span>
              </span>
            </span>
            <input
              name="storytellerRole"
              required
              minLength={2}
              placeholder="Classroom Teacher / School Leader"
            />
          </label>

          <label className="full-width">
            <span className="portal-field-label">
              <span>School Profile</span>
              <span className="portal-required-indicator">
                *<span className="visually-hidden">required</span>
              </span>
            </span>
            <select
              name="schoolId"
              value={selectedSchoolId ?? ""}
              onChange={(event) =>
                setSelectedSchoolId(event.target.value ? Number.parseInt(event.target.value, 10) : null)
              }
              required
            >
              <option value="">Select school profile</option>
              {schoolOptions.map((entry) => (
                <option key={entry.id} value={entry.id}>
                  {entry.name} ({entry.district})
                </option>
              ))}
            </select>
            <small className="portal-field-help">
              {selectedSchool
                ? `${selectedSchool.region} • ${selectedSchool.subRegion} • ${selectedSchool.district}`
                : "Every change story must be linked to a school profile."}
            </small>
          </label>

          <label className="full-width">
            <span className="portal-field-label">Story title</span>
            <input
              name="storyTitle"
              required
              minLength={6}
              placeholder="e.g. Reading recovery in Dokolo cluster schools"
            />
          </label>

          <label className="full-width">
            <span className="portal-field-label">
              <span>Baseline challenge</span>
              <span className="portal-required-indicator">
                *<span className="visually-hidden">required</span>
              </span>
            </span>
            <textarea
              name="baselineChallenge"
              required
              minLength={20}
              rows={4}
              placeholder="What was the literacy challenge before support started?"
            />
          </label>

          <label className="full-width">
            <span className="portal-field-label">
              <span>What happened</span>
              <span className="portal-required-indicator">
                *<span className="visually-hidden">required</span>
              </span>
            </span>
            <textarea
              name="whatHappened"
              required
              minLength={20}
              rows={4}
              placeholder="What support actions were implemented in the school?"
            />
          </label>

          <label className="full-width">
            <span className="portal-field-label">
              <span>Measurable change observed</span>
              <span className="portal-required-indicator">
                *<span className="visually-hidden">required</span>
              </span>
            </span>
            <textarea
              name="measurableChange"
              required
              minLength={20}
              rows={4}
              placeholder="What changed for teaching and learners? Include measurable evidence."
            />
          </label>

          <label className="full-width">
            <span className="portal-field-label">Recommendation / next steps (optional)</span>
            <textarea
              name="nextSteps"
              rows={3}
              placeholder="What should happen next to sustain gains?"
            />
          </label>

          <label className="full-width">
            <span className="portal-field-label">
              <span>Additional narrative (optional)</span>
            </span>
            <textarea
              name="storyText"
              minLength={10}
              rows={5}
              placeholder="Optional free-form context for the full change story."
            />
            <small className="portal-field-help">
              This is optional. Structured sections above are used to render summaries and details.
            </small>
          </label>

          <label>
            <span className="portal-field-label">YouTube Video Title (optional)</span>
            <input
              name="youtubeVideoTitle"
              minLength={3}
              placeholder="Paste the exact YouTube title from your channel"
            />
            <small className="portal-field-help">
              Optional: if provided, the system links matching YouTube evidence.
            </small>
          </label>
          <label>
            <span className="portal-field-label">YouTube Channel ID (optional)</span>
            <input
              name="youtubeChannelId"
              placeholder="e.g. UCxxxxxxxxxxxxxxxx"
            />
            <small className="portal-field-help">
              Optional override. Leave blank to use the default configured channel.
            </small>
          </label>

          <label>
            <span className="portal-field-label">
              <span>Video File Name Match (optional)</span>
            </span>
            <input
              name="video"
              type="file"
              accept="video/*,.mp4,.mov,.webm,.m4v"
              onChange={(event) =>
                setSelectedVideo(event.currentTarget.files?.[0] ?? null)
              }
            />
            <small className="portal-field-help">
              Optional helper only. If added, the file name can help match the YouTube title.
            </small>
          </label>
          <label>
            <span className="portal-field-label">Story Photo (optional)</span>
            <input
              name="photo"
              type="file"
              accept="image/*,.jpg,.jpeg,.png,.webp,.avif"
              onChange={(event) =>
                setSelectedPhoto(event.currentTarget.files?.[0] ?? null)
              }
            />
            <small className="portal-field-help">
              Allowed images up to 20MB.
            </small>
          </label>

          <div className="full-width">
            <p className="portal-muted">
              {selectedVideo
                ? `Video filename selected for title matching: ${selectedVideo.name}`
                : "No video file selected for title matching."}
            </p>
            <p className="portal-muted">
              {selectedPhoto
                ? `Photo selected: ${selectedPhoto.name} (${Math.max(1, Math.round(selectedPhoto.size / 1024))} KB)`
                : "No photo selected."}
            </p>
          </div>

          <div className="full-width action-row portal-form-actions">
            <button className="button" type="submit" disabled={saving}>
              {saving ? "Uploading..." : "Publish change story"}
            </button>
            <button
              className="button button-ghost"
              type="button"
              disabled={saving}
              onClick={() => {
                setFormKey((prev) => prev + 1);
                setSelectedSchoolId(defaultSchoolId ?? null);
                setSelectedVideo(null);
                setSelectedPhoto(null);
                setPlayingVideoIds({});
                setFeedback({ kind: "idle", message: "" });
              }}
            >
              Reset form
            </button>
            <button
              className="button button-ghost"
              type="button"
              disabled={saving}
              onClick={() => setIsCreateOpen(false)}
            >
              Cancel
            </button>
          </div>
        </form>
      </FloatingSurface>
    </div>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import type {
  GraduationEligibilityRecord,
  SchoolAccountProfile,
  SchoolSupportStatusRecord,
} from "@/lib/types";
import { EnrollmentFormModal } from "./EnrollmentFormModal";
import { LiteracyImpactFormModal } from "./LiteracyImpactFormModal";
import type { SchoolEnrollmentRecord, SchoolLiteracyImpactRecord } from "@/lib/types";
import { GraduationReviewModal } from "./GraduationReviewModal";

type SupervisorOption = {
  id: number;
  fullName: string;
};

interface SchoolProfileViewProps {
  profile: SchoolAccountProfile;
}

function formatDate(value: string | null | undefined) {
  if (!value) {
    return "-";
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return new Intl.DateTimeFormat("en-UG", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).format(date);
}

function formatDateTime(value: string | null | undefined) {
  if (!value) {
    return "-";
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return new Intl.DateTimeFormat("en-UG", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  }).format(date);
}

function formatNumber(value: number | null | undefined) {
  return Number(value ?? 0).toLocaleString();
}

function formatYesNo(value: boolean) {
  return value ? "Yes" : "No";
}


export function SchoolProfileView({ profile }: SchoolProfileViewProps) {
  const { school, counts, recentTrainings, recentInteractions, summary, progress } = profile;
  const [activeTab, setActiveTab] = useState<"details" | "metrics" | "contacts" | "related" | "trainings" | "interactions">("details");
  const [graduationLoading, setGraduationLoading] = useState(false);
  const [graduationError, setGraduationError] = useState("");
  const [graduationOpen, setGraduationOpen] = useState(false);
  const [enrollmentOpen, setEnrollmentOpen] = useState(false);
  const [literacyImpactOpen, setLiteracyImpactOpen] = useState(false);

  const [enrollments, setEnrollments] = useState<SchoolEnrollmentRecord[]>([]);
  const [literacyImpacts, setLiteracyImpacts] = useState<SchoolLiteracyImpactRecord[]>([]);
  const [metricsLoading, setMetricsLoading] = useState(false);
  const [graduationEligibility, setGraduationEligibility] = useState<GraduationEligibilityRecord | null>(null);
  const [graduationSupervisors, setGraduationSupervisors] = useState<SupervisorOption[]>([]);
  const [supportStatusLoading, setSupportStatusLoading] = useState(false);
  const [supportStatusError, setSupportStatusError] = useState("");
  const [schoolSupportStatus, setSchoolSupportStatus] = useState<SchoolSupportStatusRecord | null>(null);

  useEffect(() => {
    let active = true;
    setGraduationLoading(true);
    setGraduationError("");

    fetch(`/api/portal/graduation/school/${school.id}`, { cache: "no-store" })
      .then(async (response) => {
        const json = (await response.json()) as {
          eligibility?: GraduationEligibilityRecord;
          supervisors?: SupervisorOption[];
          error?: string;
        };
        if (!response.ok || !json.eligibility) {
          throw new Error(json.error ?? "Could not load graduation status.");
        }
        if (!active) {
          return;
        }
        setGraduationEligibility(json.eligibility);
        setGraduationSupervisors(Array.isArray(json.supervisors) ? json.supervisors : []);
      })
      .catch((error) => {
        if (active) {
          setGraduationError(error instanceof Error ? error.message : "Could not load graduation status.");
        }
      })
      .finally(() => {
        if (active) {
          setGraduationLoading(false);
        }
      });

    return () => {
      active = false;
    };
  }, [school.id]);

  useEffect(() => {
    let active = true;
    setSupportStatusLoading(true);
    setSupportStatusError("");
    fetch(`/api/portal/automation/support-status?type=school&schoolId=${school.id}&limit=1`, {
      cache: "no-store",
    })
      .then(async (response) => {
        const json = (await response.json()) as {
          records?: SchoolSupportStatusRecord[];
          error?: string;
        };
        if (!response.ok) {
          throw new Error(json.error ?? "Could not load school support status.");
        }
        if (!active) {
          return;
        }
        const first = Array.isArray(json.records) && json.records.length > 0 ? json.records[0] : null;
        setSchoolSupportStatus(first);
      })
      .catch((error) => {
        if (active) {
          setSupportStatusError(error instanceof Error ? error.message : "Could not load school support status.");
        }
      })
      .finally(() => {
        if (active) {
          setSupportStatusLoading(false);
        }
      });

    return () => {
      active = false;
    };
  }, [school.id]);

  function fetchMetricsHistory() {
    setMetricsLoading(true);
    Promise.all([
      fetch(`/api/portal/schools/${school.id}/enrollments`).then((r) => r.json()),
