export async function listPortalEvidencePostgres(filters?: any, user?: any): Promise<any[]> {
    const params: any[] = [];
    let query = `
      SELECT 
        id, 
        record_id AS "recordId", 
        module, 
        date, 
        school_name AS "schoolName", 
        file_name AS "fileName", 
        stored_path AS "storedPath", 
