    if (filters?.module) {
        params.push(filters.module);
        query += ` AND module = $${params.length}`;
    }
    if (filters?.dateFrom) {
        params.push(filters.dateFrom);
        query += ` AND date >= $${params.length}`;
    }
    if (filters?.dateTo) {
        params.push(filters.dateTo);
        query += ` AND date <= $${params.length}`;
