    clauses.push(`e.entity_type = $${params.length}`);
  }
  if (filters.severity) {
    params.push(filters.severity);
    clauses.push(`e.severity = $${params.length}`);
  }
  if (filters.status) {
    params.push(filters.status);
    clauses.push(`e.status = $${params.length}`);
  }
  if (filters.ruleCode) {
