      [planId]
    );

    return {
      ...plan,
      planId: Number(plan.planId),
      schoolId: plan.schoolId ? Number(plan.schoolId) : null,
      targetMetrics: JSON.parse(plan.targetMetricsJson || "{}"),
      actions: actionsResult.rows.map((a) => ({
